package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.EvenredigeVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.VrbrwWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VRIJWILLIGE_BRANDWEER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VRIJWILLIGE_BRANDWEER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

@Slf4j
public class BerekenBvVrijwilligeBrandweer extends AbstractBerekenBv {

    public BerekenBvVrijwilligeBrandweer(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        initFiscaleConstanten(rekenTijd);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Money bedrijfsvoorheffing = Money.ZERO;
        Persoon persoonKwartaalSimpel = persoonsDataManager.getPersoonKwartaalSimpel();
        if (RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel)) {
            Collection<LoonElement> loonElementen = RekenTools.filter(manager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
            Money belastbaar = RekenTools.getSomProperty(BELASTBAAR_KEY, loonElementen);
            log.debug("belastbaar:{}", belastbaar);
            Collection<LoonElement> prevLoonElementen = bepaalPrevLoonElementen(mainContext);
            Money prevBelastbaar = RekenTools.getSomProperty(BELASTBAAR_KEY, prevLoonElementen);
            Money belastbaarOther = persoonsDataManager.getBelastbaarOtherVrijwilligeBrandweer();
            Money belastbaarTotaal = belastbaar.subtract(prevBelastbaar).add(belastbaarOther);
            log.debug("belastbaar cumul VrBr:{}", belastbaarTotaal);
            if (belastbaarTotaal.signum() > 0) {
                PersoonsFiscaliteit persoonsFiscaliteit = persoonsDataManager.getPersoonsFiscaliteitOpStartFiscaalJaar();
                bedrijfsvoorheffing = berekenBvVrijwilligeBrandweer(belastbaarTotaal, persoonKwartaalSimpel, rekenTijd, persoonsFiscaliteit, regulManager);
                Money bedrijfsvoorheffingOther = persoonsDataManager.getBedrijfsvoorheffingOtherVrijwilligeBrandweer();

                bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(bedrijfsvoorheffingOther);
            }
            RekenBvKey bvKey =
                    rekenTijd.isAchterstal ? BEDRIJFSVOORHEFFING_ACHTERSTAL_VRIJWILLIGE_BRANDWEER_KEY : BEDRIJFSVOORHEFFING_VRIJWILLIGE_BRANDWEER_KEY;
            RekenBbKey bbKey = rekenTijd.isAchterstal ? BELASTBAAR_ACHTERSTAL_KEY : BELASTBAAR_KEY;
            Money bbTotaal = RekenTools.getSomProperty(bbKey, loonElementen);
            if (bbTotaal.signum() != 0) {
                BedragVerdelerFactory
                        .verdeelBedragVolgensBasisAdd(bvKey, bedrijfsvoorheffing, bbKey, bbTotaal, loonElementen, BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
            } else {
                EvenredigeVerdelerFactory.verdeelEvenredigAdd(bvKey, bedrijfsvoorheffing, loonElementen, BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
            }
        }

        return CONTINUE_PROCESSING;
    }

    private Money berekenBvVrijwilligeBrandweer(
            Money belastbaar, Persoon persoon, RekenTijd rekenTijd, PersoonsFiscaliteit persoonsFiscaliteit, RegulManager regulManager) {
        Money bedrijfsvoorheffing = Money.ZERO;
        VrbrwWrkwBv fiscaleWerkwijze = persoonsFiscaliteit.getWerkwijzeVrijwilligeBrandweer();
        log.debug("{};fiscaleWerkwijze:{}", LogTools.toSimpleLog(persoon), fiscaleWerkwijze);
        switch (fiscaleWerkwijze) {
            case BAREMA:
            case BAREMA_GFV:
                bedrijfsvoorheffing = berekenToevalligeVergoedingenBarema(belastbaar, rekenTijd);
                break;
            case PERCENTAGE_GFV:
            case PERCENTAGE:
                BigDecimal percentage = persoonsFiscaliteit.getPercentageVrijwilligeBrandweer().movePointLeft(2);
                log.debug("percentage:{}", percentage);
                bedrijfsvoorheffing = belastbaar.multiply(percentage).round(2);
                break;
            case NVT:
                //doe niets
                break;
            default:
                regulManager.doRegulException(null, Regulkode.NIET_GEPROGRAMMEERD);
                break;
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

    private Collection<LoonElement> bepaalPrevLoonElementen(RekenContext mainContext) {
        Collection<be.schaubroeck.lpb.rkm.rekenmotor.LoonElement> prevLoonElementen = be.schaubroeck.lpb.rkm.rekenmotor.LoonElement.createSortedSet();
        RekenContext preBerekeningContext = mainContext.getUnchecked(PRE_BEREKENING_CONTEXT_VORIG_FISCAAL_JAAR_KEY);
        if (preBerekeningContext != null && !preBerekeningContext.isEmpty()) {
            LoonElementManager prevManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
            prevLoonElementen = RekenTools.filter(prevManager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
        }
        return prevLoonElementen;
    }

}
